        MarkdownEditorCommand(id: "grimoire_mermaid_sequence", title: "Sequence Diagram", subtitle: "Show messages across people, apps, or agents.", aliases: ["sequence", "messages", "protocol", "api flow"], group: .technical, markdownTemplate: "```mermaid\nsequenceDiagram\n  participant User\n  participant Grimoire\n  participant Agent\n  User->>Grimoire: Ask with context\n  Grimoire->>Agent: Send note snapshot\n  Agent-->>Grimoire: Stream answer\n```"),
        MarkdownEditorCommand(id: "grimoire_mermaid_class", title: "Class Diagram", subtitle: "Sketch objects, models, and contracts.", aliases: ["class", "uml", "model", "schema"], group: .technical, markdownTemplate: "```mermaid\nclassDiagram\n  class Note {\n    +String title\n    +String path\n  }\n  class Spelllink {\n    +String target\n  }\n  Note --> Spelllink\n```"),
