        MarkdownEditorCommand(id: "grimoire_mermaid_journey", title: "Journey Map", subtitle: "Map a user or thinking journey.", aliases: ["journey", "user journey", "experience map"], group: .technical, markdownTemplate: "```mermaid\njourney\n  title Note-making flow\n  section Capture\n    Quick thought: 5: User\n    Add Spelllink: 4: User\n  section Reuse\n    Ask agent: 4: User, Agent\n```"),
        MarkdownEditorCommand(id: "grimoire_mermaid_timeline", title: "Timeline", subtitle: "Capture events in chronological order.", aliases: ["timeline", "history", "events", "chronology"], group: .technical, markdownTemplate: "```mermaid\ntimeline\n  title Project history\n  2026-05-01 : Editor package split\n  2026-05-03 : Canvas contract\n  2026-05-07 : Visual refresh\n```"),
        MarkdownEditorCommand(id: "grimoire_mermaid_mindmap", title: "Mindmap", subtitle: "Branch concepts from one idea.", aliases: ["mindmap", "brainstorm", "concept map", "map"], group: .technical, markdownTemplate: "```mermaid\nmindmap\n  root((Grimoire))\n    Markdown\n      Spelllinks\n      Mermaid\n    Canvas\n      Ink\n      Whiteboard\n    Agents\n      Claude\n      Codex\n      Chitragupta\n```"),
        MarkdownEditorCommand(id: "grimoire_mermaid_use_case", title: "Use Case Diagram", subtitle: "Represent use cases as a Mermaid flowchart.", aliases: ["use case", "case diagram", "actor", "uml use case"], group: .technical, markdownTemplate: "```mermaid\nflowchart LR\n  User((Writer))\n  Agent((AI Agent))\n  User --> Create[Create note]\n  User --> Link[Link notes]\n  Agent --> Suggest[Suggest context]\n  Suggest --> Link\n```"),
        MarkdownEditorCommand(id: "grimoire_mermaid_git_graph", title: "Git Graph", subtitle: "Show branch and merge history.", aliases: ["git", "branch", "merge", "version graph"], group: .technical, markdownTemplate: "```mermaid\ngitGraph\n  commit id: \"start\"\n  branch feature\n  checkout feature\n  commit id: \"canvas\"\n  checkout main\n  merge feature\n```")
