        MarkdownEditorCommand(id: "grimoire_pranayama_log", title: "Pranayama Log", subtitle: "Track breath ratio, rounds, duration, and nervous-system state.", aliases: ["pranayama", "breath", "nadi shodhana", "bhramari", "breathwork"], group: .practice, markdownTemplate: "## Pranayama Log - {today} {time}\n\n| Practice | Ratio | Rounds | Duration |\n| --- | --- | ---: | --- |\n| Nadi Shodhana | 4:4:8:4 |  |  |\n\nBefore\n- Breath:\n- Mind:\n\nAfter\n- Breath:\n- Mind:"),
